def compute_score() -> tuple[str, float]:
    # Use a VLM to compare original vs modified slide 5 and detect image deletions
    # Find slide 5 screenshots
    orig_img = None
    mod_img = None
    # original
    for s in original_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 5:
                orig_img = getattr(s, 'image_path', None)
                if not orig_img and isinstance(s, dict):
                    orig_img = s.get('image_path') or s.get('path')
                break
        except Exception:
            continue
    # modified
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 5:
                mod_img = getattr(s, 'image_path', None)
                if not mod_img and isinstance(s, dict):
                    mod_img = s.get('image_path') or s.get('path')
                break
        except Exception:
            continue

    if not mod_img:
        return "Modified slide 5 screenshot not found.", 0.0
    if not orig_img:
        return "Original slide 5 screenshot not found.", 1.0  # Can't penalize without baseline

    prompt = (
        "Compare these two images of slide 5: the first is ORIGINAL, the second is MODIFIED.\n"
        "Count the number of distinct images/photos/graphics/icons/charts on each slide.\n"
        "Ignore background theme images and pure text.\n"
        "Respond in EXACTLY this format with integers only (no extra words):\n"
        "ORIGINAL: <number>\nMODIFIED: <number>"
    )

    try:
        response = vlm_call(images=[orig_img, mod_img], prompt=prompt, temperature=0.1)
        txt = str(response).strip()

        # Robustly parse two integers from the response
        import re
        m1 = re.search(r"ORIGINAL\s*:\s*(\d+)", txt, flags=re.IGNORECASE)
        m2 = re.search(r"MODIFIED\s*:\s*(\d+)", txt, flags=re.IGNORECASE)
        if m1 and m2:
            orig_count = int(m1.group(1))
            mod_count = int(m2.group(1))
        else:
            nums = re.findall(r"\d+", txt)
            if len(nums) >= 2:
                orig_count = int(nums[0])
                mod_count = int(nums[1])
            else:
                return f"Could not parse image counts from VLM response: {response}", 0.0

        if orig_count == 0:
            return "No images found on original slide 5.", 1.0
        if mod_count == 0:
            return "All images were deleted from slide 5.", 1.0
        if mod_count < orig_count:
            removed = orig_count - mod_count
            return f"Some images deleted: {removed}/{orig_count} removed.", (mod_count / orig_count)
        return "No images were deleted from slide 5.", 0.0

    except Exception as e:
        return f"Error during VLM comparison: {str(e)}", 0.0

def compute_score():
    import pptx
    from pptx import Presentation
    prs = pptx.Presentation(modified_ppt_path)
    slide = prs.slides[4]
    required_texts = [
        'Image Placeholder - Eye Examination 1',
        'Image Placeholder - Eye Examination 2'
    ]
    found_texts = set()

    def _normalize(text: str) -> str:
        # Remove zero-width spaces and collapse all whitespace/newlines to single spaces
        try:
            text = text.replace('\u200b', ' ')
        except Exception:
            pass
        # Collapse all whitespace sequences (including newlines, tabs) to single spaces
        return ' '.join(text.split())

    normalized_required = [_normalize(t) for t in required_texts]
    for shape in slide.shapes:
        if shape.has_text_frame:
            text = _normalize(shape.text_frame.text)
            for req_txt, norm_req in zip(required_texts, normalized_required):
                if norm_req in text:
                    found_texts.add(req_txt)
    missing = set(required_texts) - found_texts
    if not missing:
        return "Textbox with both required texts found on slide 5.", 1.0
    elif found_texts:
        return f"Only found: {', '.join(found_texts)}. Missing: {', '.join(missing)}.", len(found_texts)/2.0
    else:
        return "No textbox with required texts found on slide 5.", 0.0
